import React, { useEffect, useState } from "react";
import API from "../../api/api";
import FreelancerLayout from "../../components/FreelancerLayout";

const FreelancerDashboard = () => {
  const user = JSON.parse(localStorage.getItem("user"));

  const [stats, setStats] = useState({
    totalProjects: 0,
    totalProposals: 0,
    acceptedProposals: 0,
    pendingProposals: 0,
  });

  const [projects, setProjects] = useState([]);

  // ===============================
  // FETCH DASHBOARD DATA
  // ===============================
  const fetchDashboard = async () => {
    try {
      const projectsRes = await API.get("/projects");
      const proposalsRes = await API.get(
        "/proposals/freelancer/my-proposals"
      );

      const proposals = proposalsRes.data;

      setStats({
        totalProjects: projectsRes.data.length,
        totalProposals: proposals.length,
        acceptedProposals: proposals.filter(
          (p) => p.status === "accepted"
        ).length,
        pendingProposals: proposals.filter(
          (p) => p.status === "pending"
        ).length,
      });

      setProjects(projectsRes.data);
    } catch (error) {
      console.log(error);
    }
  };

  useEffect(() => {
    fetchDashboard();
  }, []);

  return (
    <FreelancerLayout>
      <div className="p-8">

        {/* HEADER */}
        <h1 className="text-3xl font-bold mb-1">
          Welcome back, {user?.name || "Freelancer"} 👋
        </h1>

        <p className="text-gray-500 mb-6">
          Here's your freelancing overview
        </p>

        {/* STATS */}
        <div className="grid grid-cols-4 gap-6 mb-6">

          {/* Active Projects */}
          <div className="bg-white p-6 rounded-xl shadow flex justify-between items-center">
            <div>
              <p className="text-gray-500">Active Projects</p>
              <h2 className="text-3xl font-bold">
                {stats.totalProjects}
              </h2>
            </div>
            <div className="bg-green-500 text-white p-3 rounded-lg">
              📁
            </div>
          </div>

          {/* Total Proposals */}
          <div className="bg-white p-6 rounded-xl shadow flex justify-between items-center">
            <div>
              <p className="text-gray-500">Total Proposals</p>
              <h2 className="text-3xl font-bold">
                {stats.totalProposals}
              </h2>
            </div>
            <div className="bg-green-500 text-white p-3 rounded-lg">
              📨
            </div>
          </div>

          {/* Accepted */}
          <div className="bg-white p-6 rounded-xl shadow flex justify-between items-center">
            <div>
              <p className="text-gray-500">Accepted</p>
              <h2 className="text-3xl font-bold">
                {stats.acceptedProposals}
              </h2>
            </div>
            <div className="bg-green-500 text-white p-3 rounded-lg">
              ✅
            </div>
          </div>

          {/* Pending */}
          <div className="bg-white p-6 rounded-xl shadow flex justify-between items-center">
            <div>
              <p className="text-gray-500">Pending</p>
              <h2 className="text-3xl font-bold">
                {stats.pendingProposals}
              </h2>
            </div>
            <div className="bg-green-500 text-white p-3 rounded-lg">
              ⏱️
            </div>
          </div>
        </div>

        {/* PROJECT SECTION */}
        <div className="grid grid-cols-3 gap-6">

          {/* LEFT SIDE */}
          <div className="col-span-2">
            <h2 className="text-xl font-bold mb-4">
              Active Projects
            </h2>

            {projects.length === 0 && (
              <p className="text-gray-500">
                No projects available
              </p>
            )}

            {projects.map((project) => (
              <div
                key={project.id}
                className="bg-white p-6 rounded-xl shadow mb-4"
              >
                <h3 className="font-bold text-lg">
                  {project.title}
                </h3>

                <p className="text-gray-500">
                  {project.description}
                </p>

                <p className="text-green-600 font-bold mt-2">
                  ₹ {project.budget}
                </p>
              </div>
            ))}
          </div>

          {/* RIGHT PROFILE */}
          <div className="bg-white p-6 rounded-xl shadow">
            <h2 className="text-xl font-bold mb-4">
              Profile Completion
            </h2>

            <Progress label="Basic Info" value="100%" />
            <Progress label="Portfolio" value="75%" />
            <Progress label="Skills" value="90%" />
            <Progress label="Certifications" value="40%" />
          </div>

        </div>

      </div>
    </FreelancerLayout>
  );
};

const Progress = ({ label, value }) => (
  <div className="mb-4">
    <div className="flex justify-between">
      <p>{label}</p>
      <p>{value}</p>
    </div>

    <div className="w-full bg-gray-200 h-2 rounded">
      <div
        className="bg-green-500 h-2 rounded"
        style={{ width: value }}
      ></div>
    </div>
  </div>
);

export default FreelancerDashboard;
